      | "NotFoundException" ->
          `NotFoundException (NotFoundException.of_json json)
      | "OperationFailureException" ->
          `OperationFailureException (OperationFailureException.of_json json)
      | "ServiceException" ->
          `ServiceException (ServiceException.of_json json)
      | "UnauthenticatedException" ->
          `UnauthenticatedException (UnauthenticatedException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_xml xml)
      | "AccountSetupInProgressException" ->
          `AccountSetupInProgressException
            (AccountSetupInProgressException.of_xml xml)
      | "InvalidInputException" ->
          `InvalidInputException (InvalidInputException.of_xml xml)
      | "NotFoundException" ->
          `NotFoundException (NotFoundException.of_xml xml)
      | "OperationFailureException" ->
          `OperationFailureException (OperationFailureException.of_xml xml)
      | "ServiceException" -> `ServiceException (ServiceException.of_xml xml)
      | "UnauthenticatedException" ->
          `UnauthenticatedException (UnauthenticatedException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedException e ->
          `Assoc
            [("error", (`String "AccessDeniedException"));
            ("details", (AccessDeniedException.to_json e))]
      | `AccountSetupInProgressException e ->
          `Assoc
            [("error", (`String "AccountSetupInProgressException"));
            ("details", (AccountSetupInProgressException.to_json e))]
      | `InvalidInputException e ->
          `Assoc
            [("error", (`String "InvalidInputException"));
            ("details", (InvalidInputException.to_json e))]
      | `NotFoundException e ->
          `Assoc
            [("error", (`String "NotFoundException"));
            ("details", (NotFoundException.to_json e))]
      | `OperationFailureException e ->
          `Assoc
            [("error", (`String "OperationFailureException"));
            ("details", (OperationFailureException.to_json e))]
      | `ServiceException e ->
          `Assoc
            [("error", (`String "ServiceException"));
            ("details", (ServiceException.to_json e))]
      | `UnauthenticatedException e ->
          `Assoc
            [("error", (`String "UnauthenticatedException"));
            ("details", (UnauthenticatedException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
